#!/usr/bin/python3
import sys

class Solution:
    def solve(self, nums: list[int]) -> int:
        minElement = min(nums)
        minIndex = nums.index(minElement)
        for i in range(len(nums)):
            if nums[i] == minElement:
                minIndex = i
                break
        for i in range(1, len(nums)):
            if nums[i] < nums[i-1]:
                return i
        return len(nums)

solution = Solution()

nums = list(map(int, input().split()))

print(solution.solve(nums))

