#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution {
public:
    int solve(vector<int>& nums) {
        int minElement = *min_element(nums.begin(), nums.end());
        int minIndex = (lower_bound(nums.begin(), nums.end(), minElement) - nums.begin());
        for (int i = 0; i < nums.size(); i++) { if (nums[i] == minElement) { minIndex = i; break; } }
        for (int i = 1; i < nums.size(); i++) { if (nums[i] < nums[i-1]) { return i; } }
        return nums.size();
    }
};

int main() {
    Solution solution;
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) {
        cin >> nums[i];
    }

    cout << solution.solve(nums) << endl;
